    invariant b == CountVal(doors[..i], 1)
  {
    assert doors[i] == 0 || doors[i] == 1;
    assert a + b == i;
    if doors[i] == 0 {
      a := a + 1;
    } else {
      b := b + 1;
    }
    i := i + 1;
  }
  assert a == CountVal(doors, 0);

